query:
ALTER TABLE plans ADD COLUMN maxAiGenerations INT NOT NULL DEFAULT 0 COMMENT '-1 for unlimited, 0 for none';
UPDATE plans SET maxAiGenerations = CASE 
  WHEN hasAiGeneration = 1 THEN -1 
  ELSE 0 
END;
ALTER TABLE plans DROP COLUMN hasAiGeneration;

